const now = new Date().toISOString();
const drillMode = $env.CONTROL_PLANE_DRILL === '1';
return [
  {
    json: {
      source: drillMode ? 'manual-drill' : 'scheduled-mock',
      cost: drillMode ? 44 : 28.3,
      budget: 40,
      windowHours: 24,
      currency: 'USD',
      timestamp: now,
      detail: drillMode ? 'Control-plane drill payload for Cost Governor' : 'Scheduled mock input to keep Cost Governor fresh',
      metadata: {
        cohort: 'cost-governor-demo',
        cadence: '60m',
        drillMode
      }
    }
  }
];

const raw = $input.first().json;
const now = new Date().toISOString();
const costValue = Number(raw.cost ?? raw.totalCost ?? raw.estimatedCost ?? 0);
const budgetValue = Number(raw.budget ?? raw.monthlyBudget ?? raw.allocatedBudget ?? 0);
const windowHours = Number(raw.windowHours ?? raw.window ?? 24) || 24;
const currency = raw.currency ?? 'USD';
const timestamp = raw.timestamp ?? raw.recordedAt ?? now;
const source = raw.source ?? 'webhook';
const detail = raw.detail ?? raw.notes ?? 'cost telemetry';
const metadata = {
  ...(typeof raw.metadata === 'object' ? raw.metadata : {}),
  ingestion: source === 'scheduled-mock' ? 'mock' : 'webhook',
  receivedAt: now
};
return [{
  json: {
    workflow: 'cost-governor',
    source,
    timestamp,
    cost: costValue,
    budget: budgetValue,
    windowHours,
    currency,
    detail,
    metadata
  }
}];

const payload = $input.first().json;
const cost = Number(payload.cost ?? 0);
const budget = Number(payload.budget ?? 0);
const windowHours = Math.max(1, Number(payload.windowHours ?? 24));
const ratio = budget > 0 ? Number((cost / budget).toFixed(4)) : 0;
const hourlyRate = Number((cost / windowHours).toFixed(4));
const projected24 = Number((hourlyRate * 24).toFixed(2));
const projectedRatio = budget > 0 ? Number((projected24 / budget).toFixed(4)) : null;
const shortfall = budget > 0 ? Number((budget - cost).toFixed(2)) : null;
const stageDefinitions = [
  {
    label: 'Observation',
    min: 0,
    max: 0.75,
    severity: 'nominal',
    condition: 'ratio < 0.75',
    rationale: 'Telemetry and War Room continue without intervention.',
    next: 'Keep watching the War Room and annotate trends for VP reviews.'
  },
  {
    label: 'Constraint',
    min: 0.75,
    max: 1,
    severity: 'warning',
    condition: '0.75 ≤ ratio < 1.0',
    rationale: 'Budget trending high; pre-authorize noncritical limits.',
    next: 'Throttle optional agents, postpone new features, log change request.'
  },
  {
    label: 'Approval Guardrail',
    min: 1,
    max: Infinity,
    severity: 'critical',
    condition: 'ratio ≥ 1.0',
    rationale: 'Budget exhausted; manual authorization required before scaling.',
    next: 'Hold automation, notify approver, and avoid cost-driving actions.'
  }
];
const activeStage = stageDefinitions.find((stage) => ratio >= stage.min && ratio < stage.max) ?? stageDefinitions[stageDefinitions.length - 1];
const mitigationLadder = stageDefinitions.map((stage) => ({
  stage: stage.label,
  severity: stage.severity,
  condition: stage.condition,
  active: ratio >= stage.min && ratio < stage.max,
  rationale: stage.rationale,
  recommendation: stage.next
}));
const requiresApproval = ratio >= 1;
const nextAction = requiresApproval ? stageDefinitions[2].next : activeStage.next;
const severityLabel = requiresApproval ? 'critical' : ratio >= 0.75 ? 'warning' : 'nominal';
const analysisSummary = requiresApproval
  ? 'Cost governor halted new agents until approval.'
  : ratio >= 0.75
    ? 'Preliminary constraints in place; runway thinning.'
    : 'Budget headroom is healthy.';
return [{
  json: {
    ...payload,
    ratio,
    hourlyRate,
    projected24,
    projectedRatio,
    shortfall,
    severity: severityLabel,
    mitigationLadder,
    nextAction,
    requiresApproval,
    analysisSummary
  }
}];

const payload = $input.first().json;
const shouldNotify = payload.source !== 'scheduled-mock' || payload.severity !== 'nominal';
const icon = payload.severity === 'critical'
  ? ':rotating_light:'
  : payload.severity === 'warning'
    ? ':warning:'
    : ':white_check_mark:';
const lines = [
  `${icon} *Cost Governor* ${String(payload.severity || 'nominal').toUpperCase()}`,
  `Source: ${payload.source}`,
  `Observed: ${payload.cost} ${payload.currency}`,
  `Budget: ${payload.budget} ${payload.currency}`,
  `Ratio: ${payload.ratio}`,
  `Projected 24h: ${payload.projected24} ${payload.currency}`,
  `Summary: ${payload.analysisSummary}`,
  `Next action: ${payload.nextAction}`
];
return [{
  json: {
    ...payload,
    slackNotification: {
      skip: !shouldNotify,
      channel: 'C0ALX8C12TG',
      text: lines.join('\n')
    }
  }
}];

const payload = $input.first().json;
const lines = [
  `:money_with_wings: *Cost Governor Approval Guardrail*`,
  `Source: ${payload.source}`,
  `Observed: ${payload.cost} ${payload.currency}`,
  `Budget: ${payload.budget} ${payload.currency}`,
  `Ratio: ${payload.ratio}`,
  `Projected 24h: ${payload.projected24} ${payload.currency}`,
  `Summary: ${payload.analysisSummary}`,
  `Action requested: ${payload.nextAction}`
];
return [{
  json: {
    ...payload,
    approvalNotification: {
      skip: payload.requiresApproval !== true,
      channel: 'C0AM2TREPN0',
      text: lines.join('\n')
    }
  }
}];
